using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");

// In .NET 9+ there's also the generic helper on the options:
JsonTypeInfo<Person> personInfo2 = options.GetTypeInfo<Person>();
Console.WriteLine($"Generic GetTypeInfo<T> returned: {personInfo2.Type.Name}");

// 2) Probe without throwing: TryGetTypeInfo returns false if unavailable
//    Use an empty resolver so nothing is resolvable
var emptyOptions = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // resolves nothing
};

bool found = emptyOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"\nTryGetTypeInfo with empty resolver => found: {found}, info: {info?.Type.Name ?? "(null)"}");

// And confirm it works when metadata IS available
bool found2 = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2);
Console.WriteLine($"TryGetTypeInfo with real resolver  => found: {found2}, info: {info2?.Type.Name ?? "(null)"}");

public record Person(string Name, int Age);

